#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    int x = *(int*)b - *(int*)a;
    return x;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int L, H; scanf("%d %d", &L, &H);
        char *S = (char*)malloc(L+5);
        scanf("%s", S);
        int *segs = (int*)malloc(L * sizeof(int));
        int cnt=0, segCnt=0;
        for(int i=0;i<L;i++){
            if(S[i]=='0') cnt++;
            else{ if(cnt>0){ segs[segCnt++]=cnt; cnt=0; } }
        }
        if(cnt>0) segs[segCnt++]=cnt;
        qsort(segs, segCnt, sizeof(int), cmp_desc);
        int req = H;
        int ok = 0;
        for(int i=0;i<segCnt;i++){
            int len = segs[i];
            if(len >= req){ ok = 1; break; }
            if(len*2 > req) req = 2*(req - len);
        }
        printf(ok?"YES\n":"NO\n");
        free(S); free(segs);
    }
    return 0;
}

