import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int L = Integer.parseInt(st.nextToken());
            int H = Integer.parseInt(st.nextToken());
            String S = br.readLine().trim();
            List<Integer> segs = new ArrayList<>();
            int cnt = 0;
            for (int i = 0; i < L; i++) {
                if (S.charAt(i) == '0') cnt++; else { if (cnt > 0) { segs.add(cnt); cnt = 0; } }
            }
            if (cnt > 0) segs.add(cnt);
            segs.sort(Collections.reverseOrder());
            int req = H; boolean ok = false;
            for (int len : segs) {
                if (len >= req) { ok = true; break; }
                if (len * 2 > req) req = 2 * (req - len);
            }
            out.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

