import sys

def can_sleep(H, s):
    segs = []
    cnt = 0
    for ch in s:
        if ch == '0':
            cnt += 1
        else:
            if cnt:
                segs.append(cnt)
                cnt = 0
    if cnt:
        segs.append(cnt)
    segs.sort(reverse=True)
    req = H
    for length in segs:
        if length >= req:
            return True
        if length * 2 > req:
            req = 2 * (req - length)
    return False

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        L = int(next(it)); H = int(next(it))
        S = next(it)
        out_lines.append('YES' if can_sleep(H, S) else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

